import './App.css';
import About from './Companents/Frame/About';
import Home from './Companents/Frame/Home';
import Project from './Companents/Frame/Project';
import Contact from './Companents/Frame/Contact';
import Navbar from './Companents/Navbar';
import { BrowserRouter, Route, Routes } from "react-router-dom";

function App() {
  return (
    <div className="App">
    <Navbar/>
    <BrowserRouter>
      <Routes>
        <Route path="/" element={<Home/>} />
        <Route path="About" element={<About/>} />
        <Route path="Project" element={<Project/>} />
        <Route path="Contact" element={<Contact/>} />
      </Routes>
    </BrowserRouter>
    </div>
  );
}

export default App;
